// MM_TYPE *nn_mat_mul_kernel_tiling(const MM_TYPE * src1,
//                                   const MM_TYPE * src2,
//                                   MM_TYPE_VQ * tmp_out,
//                                   MM_TYPE * out,
//                                   const uint16_t row,
//                                   const uint16_t col,
//                                   const uint16_t col2,
//                                   const MM_TYPE * bias,
//                                   const uint16_t tiling_size)
// {
// #ifdef ENA_VEC_ISA
#ifdef ENA_DYNAMIC_CALC_CACHE_CONFIG
    unsigned int cache_size_byte = 0, tiling_size = 1;
    vec_calc_tiling_size_and_cache_config(&cache_size_byte, &tiling_size);
#else
    //cache is 512KB
    const unsigned int cache_size_byte = 512 << 10;
#endif
    unsigned int tiling_row_B;
    //col > 8: assume max way is 8 to prevent /0
    if(col < tiling_size && col > 8)
    {
        tiling_row_B = higher_power_2(col);
    }
    else
    {
        tiling_row_B = tiling_size;
    }
    /*
    //4096(col2) * 1B(q7) = 4096B
    //4096B / 64B(line) = 64(row offset of B)
    //2048(line per way) / 64 = 32
    //32 * 4(way) = 128(total num of B in cache)
    //256(tiling_size) is 2 times the 128, second half 128 will cause first half 128 be all evicted
    */
    unsigned int min_col2_byte = cache_size_byte / (tiling_row_B >> 1);

    //packing can handle just full cache
    min_col2_byte = min_col2_byte >> 1;
    int rvv = RVV_TILING;
    unsigned int col2_byte = col2 * sizeof(MM_TYPE);   //byte of row of B

    //col2 big enough
    if(col2_byte >= min_col2_byte)
    {
        rvv = RVV_PACKING;
    }

    //small_matrix also use original_rvv
    unsigned int total = ((row * col) + (col * col2) + (row * col2)); //ABC size
    unsigned int max_size = tiling_size * tiling_size * 3; //max small_matrix size
    if(total < max_size)
    {
        rvv = RVV_ORIGINAL;
    }

#ifdef ENA_PACKING_HVM
    rvv = RVV_PACKING;
#endif

    if(rvv == RVV_ORIGINAL)
    {
        //original rvv
        vec_mat_mul_rvv_original_vq(src1, src2, tmp_out, row, col, col2);
    }
    else if(rvv == RVV_TILING)
    {
        /* initial output */
        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
        //4*4 by 4*vl
        vec_mat_mul_rvv_tiling_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
    }
    else if(rvv == RVV_PACKING)
    {
        /* initial output */
        nn_set_zero_s16((q15_t *)tmp_out, (row * col2 * 2));
        //packing_rvv
        int status = vec_mat_mul_rvv_packing_vq(src1, src2, tmp_out, row, col, col2, tiling_size);
        if(status == -1)
        {
            return out;
        }
    }


#ifdef CONV_BIAS
#ifdef U8_U8_S8_TYPE //output is u8
    //bias
    int vl, avl;
    for(int i = 0; i < row; i++)
    {
        avl = col2;
        const MM_TYPE_VQ *pbias = bias;
        while(avl > 0)
        {
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
            DEF_VLOADVQ_V(NDS_VEC_V16, tmp_out);
            DEF_VLOADVQ_V(NDS_VEC_V24, pbias);
            NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);
            NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V16, NDS_VEC_V16, post_rshift);
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIPU_WX(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VMERGE_VIM(NDS_VEC_V24, NDS_VEC_V16, 0);
            DEF_VSTORE_V(NDS_VEC_V24, out);
            tmp_out += vl;
            pbias += vl;
            out += vl;
            avl -= vl;
        }
    }
    return out;
#elif defined(U8_S8_S8_TYPE) || defined(S8_S8_S8_TYPE) //output is s8
    //bias
    int vl, avl;
    for(int i = 0; i < row; i++)
    {
        avl = col2;
        const MM_TYPE_VQ *pbias = bias;
        while(avl > 0)
        {
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
            DEF_VLOADVQ_V(NDS_VEC_V0, tmp_out);
            DEF_VLOADVQ_V(NDS_VEC_V8, pbias);
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
            DEF_VSTORE_V(NDS_VEC_V0, out);
            tmp_out += vl;
            pbias += vl;
            out += vl;
            avl -= vl;
        }
    }
    return out;
#elif defined(S8_S16_S8_TYPE) || defined(U8_S16_S8_TYPE) //output is s16
    //bias
    int vl, avl;
    for(int i = 0; i < row; i++)
    {
        avl = col2;
        const MM_TYPE_VQ *pbias = bias;
        while(avl > 0)
        {
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
            DEF_VLOADVQ_V(NDS_VEC_V0, tmp_out);
            DEF_VLOADVQ_V(NDS_VEC_V8, pbias);
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
            DEF_VSTORE_V(NDS_VEC_V0, out);
            tmp_out += vl;
            pbias += vl;
            out += vl;
            avl -= vl;
        }
    }
    return out;
#endif
#else //non-bias
#ifdef U8_U8_S8_TYPE //output is u8
    int vl, avl;
    for(int i = 0; i < row; i++)
    {
        avl = col2;
        while(avl > 0)
        {
